args.sparql:
SELECT ?person ?personLabel WHERE {
  ?person wdt:P39 wd:Q642859 .
  ?person wdt:P580 ?startDate .
  ?person wdt:P582 ?endDate .
  FILTER(?startDate <= "2017-12-31T00:00:00Z"^^xsd:dateTime)
  FILTER(?endDate >= "2017-01-01T00:00:00Z"^^xsd:dateTime)
  SERVICE wikibase:label { bd:serviceParam wikibase:language "en" }
  }

SELECT ?person ?personLabel WHERE {
  ?person wdt:P39 wd:Q642859 ;
          wdt:P580 ?startDate .
  OPTIONAL { ?person wdt:P582 ?endDate } .
  FILTER (?startDate <= "2017-12-31"^^xsd:date)
  FILTER ( (BOUND(?endDate) && ?endDate >= "2017-01-01"^^xsd:date) || !BOUND(?endDate) )
  ?person rdfs:label ?personLabel .
  FILTER (LANG(?personLabel) = 'en')
}

SELECT ?person ?personLabel WHERE {
  ?person wdt:P39 wd:Q642859 ;
          wdt:P580 ?startDate .
  OPTIONAL { ?person wdt:P582 ?endDate } .
  FILTER (?startDate <= "2017-12-31"^^xsd:date)
  FILTER ((BOUND(?endDate) && ?endDate >= "2017-01-01"^^xsd:date) || !BOUND(?endDate))
  ?person rdfs:label ?personLabel .
  FILTER (LANG(?personLabel) = 'en')
}
